import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
      });
  }, [doctor_id]);

  const getDayName = (dateStr) => {
    return new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });
  };

  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      alert(`Doctor not available on ${dayName}`);
      return;
    }

    setDate(selectedDate);
  };

  const handleNext = () => {
    if (!date || !time) {
      alert("Select date and time");
      return;
    }

    navigate("/appointment", {
      state: { doctor, date, time, doctor_id },
    });
  };

  if (!doctor) return <h2>Loading...</h2>;

  return (
    <div>
      <Navbar />

      <h2>{doctor.name}</h2>

      <p>Available Days: {availableDays.join(", ")}</p>

      <input
        type="date"
        value={date}
        min={new Date().toISOString().split("T")[0]}
        onChange={handleDateChange}
      />

      <select value={time} onChange={(e) => setTime(e.target.value)}>
        <option value="">Select Time</option>
        <option>10:00 AM</option>
        <option>11:00 AM</option>
        <option>2:00 PM</option>
        <option>4:00 PM</option>
      </select>

      <button onClick={handleNext}>Book</button>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    display: "flex",
    backgroundColor: "white",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "700px",
    gap: "30px",
  },

  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
  },

  right: {
    flex: 1,
  },

  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
